/**
 * @fileoverview SPA Router — hash-based routing with component rendering,
 *               reactive state integration, and lifecycle management.
 * @module module/SPA/router
 */

import { Component } from './component.js';
import { bus } from './event-bus.js';

/**
 * @typedef {object} RouteConfig
 * @property {string}            path      — hash path (e.g. '/home', '/user/:id')
 * @property {typeof Component}  component — Component class to render
 * @property {object}            [props]   — static props to pass
 * @property {Function}          [guard]   — `(to, from) => boolean | string` — return false to cancel or a path string to redirect
 */

/**
 * Hash-based SPA router.
 *
 * @example
 * const router = new Router('#app', [
 *     { path: '/',        component: Home },
 *     { path: '/about',   component: About },
 *     { path: '/user/:id', component: UserProfile },
 * ]);
 * router.start();
 */
export class Router {
    /** @type {HTMLElement} */
    #root = null;
    /** @type {RouteConfig[]} */
    #routes = [];
    /** @type {Component|null} */
    #current = null;
    /** @type {RouteConfig|null} */
    #currentRoute = null;
    /** @type {AbortController} */
    #ac = new AbortController();

    /**
     * @param {string|HTMLElement} selector — mount point
     * @param {RouteConfig[]}     routes
     */
    constructor(selector, routes = []) {
        this.#root = typeof selector === 'string'
            ? document.querySelector(selector)
            : selector;
        if (!this.#root) throw new Error(`[SPA Router] Mount point not found: ${selector}`);
        this.#routes = routes;
    }

    /** Begin listening for hash changes and render the initial route. */
    start() {
        window.addEventListener('hashchange', () => this.#onHashChange(), { signal: this.#ac.signal });
        this.#onHashChange();
    }

    /** Stop listening and unmount current component. */
    destroy() {
        this.#ac.abort();
        this.#unmountCurrent();
    }

    /**
     * Programmatic navigation.
     * @param {string} path — e.g. '/user/42'
     */
    push(path) {
        window.location.hash = '#' + path;
    }

    /**
     * Replace current hash without creating a new history entry.
     * @param {string} path
     */
    replace(path) {
        const url = new URL(window.location);
        url.hash = '#' + path;
        history.replaceState(null, '', url);
        this.#onHashChange();
    }

    /** @returns {{ path: string, params: object, query: object }|null} */
    get currentRoute() {
        if (!this.#currentRoute) return null;
        const hash = (window.location.hash || '#/').slice(1);
        const [pathname, qs] = hash.split('?');
        return {
            path: pathname,
            params: matchPath(this.#currentRoute.path, pathname)?.params || {},
            query: parseQuery(qs || ''),
        };
    }

    // ── Internal ─────────────────────────────────

    #onHashChange() {
        const hash = (window.location.hash || '#/').slice(1);
        const [pathname] = hash.split('?');
        const from = this.#currentRoute?.path ?? null;

        for (const route of this.#routes) {
            const match = matchPath(route.path, pathname);
            if (!match) continue;

            // Guard check
            if (typeof route.guard === 'function') {
                const result = route.guard(pathname, from);
                if (result === false) return;
                if (typeof result === 'string') { this.push(result); return; }
            }

            this.#mount(route, match.params);
            return;
        }

        // No matched route — try the catch-all '*'
        const fallback = this.#routes.find(r => r.path === '*');
        if (fallback) {
            this.#mount(fallback, {});
        }
    }

    /**
     * Unmount old component, instantiate and mount the new one.
     * @param {RouteConfig} route
     * @param {object} params
     */
    #mount(route, params) {
        this.#unmountCurrent();

        const hash = (window.location.hash || '#/').slice(1);
        const [, qs] = hash.split('?');
        const props = {
            ...route.props,
            params,
            query: parseQuery(qs || ''),
        };

        const instance = new route.component(props);
        instance._mount(this.#root);
        this.#current = instance;
        this.#currentRoute = route;

        bus.emit('route:change', { path: route.path, params, query: props.query });
    }

    #unmountCurrent() {
        if (this.#current) {
            this.#current._unmount();
            this.#current = null;
            // Clear the container
            this.#root.innerHTML = '';
        }
    }
}

// ── Helpers ──────────────────────────────────────

/**
 * Match a route pattern (supports `:param` segments) against a pathname.
 * @param {string} pattern  — e.g. '/user/:id'
 * @param {string} pathname — e.g. '/user/42'
 * @returns {{ params: object }|null}
 */
function matchPath(pattern, pathname) {
    if (pattern === '*') return { params: {} };

    const pParts = pattern.split('/');
    const uParts = pathname.split('/');
    if (pParts.length !== uParts.length) return null;

    const params = {};
    for (let i = 0; i < pParts.length; i++) {
        if (pParts[i].startsWith(':')) {
            params[pParts[i].slice(1)] = decodeURIComponent(uParts[i]);
        } else if (pParts[i] !== uParts[i]) {
            return null;
        }
    }
    return { params };
}

/**
 * Parse a query string into a plain object.
 * @param {string} qs
 * @returns {object}
 */
function parseQuery(qs) {
    if (!qs) return {};
    const out = {};
    for (const pair of qs.split('&')) {
        const [key, val] = pair.split('=');
        if (key) out[decodeURIComponent(key)] = val ? decodeURIComponent(val) : '';
    }
    return out;
}
