/**
 * @fileoverview Lazy component loader — load SPA components on demand,
 *               with optional loading / error placeholders (React.lazy style).
 * @module module/SPA/lazy
 */

import { h } from './vdom.js';
import { Component } from './component.js';

/**
 * Cache of resolved component classes keyed by the loader function reference.
 * @type {Map<Function, { Comp: typeof Component | null, error: Error | null, promise: Promise | null }>}
 */
const _cache = new Map();

/**
 * Lazily load a component module.  Returns a thin wrapper Component that
 * shows `fallback` while loading and delegates to the real component once
 * ready.
 *
 * @param {() => Promise<{ default: typeof Component }>} loader
 *        — A function returning a dynamic `import()` promise.
 * @param {object} [opts]
 * @param {Function} [opts.fallback]  — `(h) => VNode` shown while loading.
 * @param {Function} [opts.onError]   — `(h, error) => VNode` shown on failure.
 * @returns {typeof Component}        — A wrapper component class.
 *
 * @example
 * const AsyncProfile = lazy(() => import('./views/Profile.js'));
 *
 * // In routes:
 * { path: '/profile', component: AsyncProfile }
 */
export function lazy(loader, opts = {}) {
    const entry = _cache.get(loader) || { Comp: null, error: null, promise: null };
    if (!_cache.has(loader)) _cache.set(loader, entry);

    return class LazyWrapper extends Component {
        setup() {
            this.state = { ready: !!entry.Comp, error: entry.error };
        }

        onMount() {
            if (entry.Comp) return;
            if (!entry.promise) {
                entry.promise = loader()
                    .then(mod => { entry.Comp = mod.default || mod; })
                    .catch(err => { entry.error = err; });
            }

            entry.promise.then(() => {
                if (!this._mounted) return;
                this.setState({ ready: true, error: entry.error });
            });
        }

        render() {
            if (this.state.error) {
                return opts.onError
                    ? opts.onError(h, this.state.error)
                    : h('div', { className: 'spa-lazy-error' }, `Failed to load component`);
            }
            if (!this.state.ready || !entry.Comp) {
                return opts.fallback
                    ? opts.fallback(h)
                    : h('div', { className: 'spa-lazy-loading' }, 'Loading\u2026');
            }

            // Delegate to the real component's render
            const instance = new entry.Comp(this.props);
            return instance.render();
        }
    };
}
