/**
 * @fileoverview Global event bus — publish / subscribe system (Vue-style).
 * @module module/SPA/event-bus
 */

export class EventBus {
    /** @type {Map<string, Set<Function>>} */
    #listeners = new Map();

    /**
     * Register a listener for the given event.
     * @param {string} event
     * @param {Function} handler
     * @returns {() => void} Unsubscribe function
     */
    on(event, handler) {
        if (!this.#listeners.has(event)) this.#listeners.set(event, new Set());
        this.#listeners.get(event).add(handler);
        return () => this.off(event, handler);
    }

    /**
     * Register a one-time listener.
     * @param {string} event
     * @param {Function} handler
     * @returns {() => void} Unsubscribe function
     */
    once(event, handler) {
        const wrapper = (...args) => {
            this.off(event, wrapper);
            handler(...args);
        };
        wrapper._original = handler;
        return this.on(event, wrapper);
    }

    /**
     * Remove a specific listener, or all listeners for an event.
     * @param {string} event
     * @param {Function} [handler]
     */
    off(event, handler) {
        if (!handler) {
            this.#listeners.delete(event);
            return;
        }
        const set = this.#listeners.get(event);
        if (!set) return;
        set.delete(handler);
        // Also remove `once` wrappers whose _original matches
        for (const fn of set) {
            if (fn._original === handler) set.delete(fn);
        }
        if (set.size === 0) this.#listeners.delete(event);
    }

    /**
     * Emit an event to all registered listeners.
     * @param {string} event
     * @param {...*} args
     */
    emit(event, ...args) {
        const set = this.#listeners.get(event);
        if (!set) return;
        for (const fn of [...set]) fn(...args);
    }

    /** Remove every listener on every event. */
    clear() {
        this.#listeners.clear();
    }
}

/** Singleton bus shared across the entire app. */
export const bus = new EventBus();
