/**
 * @fileoverview SPA Hydrate — renders PHP-generated VNode JSON into live DOM.
 *
 * The PHP `Razy\DOM\Component` class emits `<div data-spa-component>` wrappers
 * containing `<script type="application/json">` with serialised VNode trees.
 * This module finds those markers and replaces them with rendered DOM via the
 * SPA virtual-DOM pipeline.
 *
 * Usage:
 *   import { hydrate, hydrateElement } from './hydrate.js';
 *
 *   // Hydrate all [data-spa-component] in the document
 *   hydrate();
 *
 *   // Hydrate a specific container (e.g. after AJAX-loaded HTML)
 *   hydrateElement(containerEl);
 *
 *   // Hydrate a batch script block
 *   hydrateBatch();
 *
 * @module module/SPA/hydrate
 */

import { createElement, patch } from './vdom.js';

/**
 * Hydrate all `[data-spa-component]` elements within a root.
 *
 * Each element should contain a `<script type="application/json">` child
 * with a serialised VNode tree (produced by `Component::render()` in PHP).
 *
 * @param {HTMLElement|Document} [root=document] — scope to search within
 * @returns {number} Number of components hydrated
 */
export function hydrate(root = document) {
    const targets = root.querySelectorAll('[data-spa-component]');
    let count = 0;

    for (const el of targets) {
        if (el.dataset.spaHydrated) continue; // already processed
        if (hydrateElement(el)) count++;
    }

    return count;
}

/**
 * Hydrate a single `[data-spa-component]` element.
 *
 * @param {HTMLElement} el — the wrapper element with embedded JSON
 * @returns {boolean} true if successfully hydrated
 */
export function hydrateElement(el) {
    const script = el.querySelector('script[type="application/json"]');
    if (!script) return false;

    let vnode;
    try {
        vnode = JSON.parse(script.textContent);
    } catch {
        console.error('[SPA hydrate] Invalid JSON in', el);
        return false;
    }

    if (!vnode || !vnode._vnode) {
        console.error('[SPA hydrate] Invalid VNode structure in', el);
        return false;
    }

    // Remove the JSON script and render the VNode tree
    script.remove();
    const dom = createElement(vnode);
    el.appendChild(dom);
    el.dataset.spaHydrated = 'true';

    return true;
}

/**
 * Hydrate batch script blocks (`<script data-spa-batch>`).
 *
 * PHP `Component::renderBatch()` emits a single JSON object mapping
 * CSS selectors to VNode trees. This function finds each target and
 * renders the VNode inside it.
 *
 * @param {HTMLElement|Document} [root=document]
 * @returns {number} Number of components hydrated
 */
export function hydrateBatch(root = document) {
    const scripts = root.querySelectorAll('script[type="application/json"][data-spa-batch]');
    let count = 0;

    for (const script of scripts) {
        let batch;
        try {
            batch = JSON.parse(script.textContent);
        } catch {
            console.error('[SPA hydrate] Invalid batch JSON');
            continue;
        }

        for (const [selector, vnode] of Object.entries(batch)) {
            if (!vnode || !vnode._vnode) continue;

            const target = root.querySelector(selector);
            if (!target) {
                console.warn(`[SPA hydrate] Batch target not found: ${selector}`);
                continue;
            }

            const dom = createElement(vnode);
            target.innerHTML = '';
            target.appendChild(dom);
            count++;
        }

        script.remove();
    }

    return count;
}

/**
 * Render a VNode JSON object (from PHP or an API response) into a
 * target element. Useful for dynamic AJAX-loaded component data.
 *
 * @param {HTMLElement} target  — element to render into
 * @param {object}      vnode  — VNode data (plain object, not yet DOM)
 * @param {object|null} prev   — previous VNode for diffing (null = fresh render)
 * @returns {object} The rendered VNode (pass as `prev` for next update)
 */
export function renderVNode(target, vnode, prev = null) {
    if (prev) {
        patch(target, prev, vnode, 0);
    } else {
        target.innerHTML = '';
        target.appendChild(createElement(vnode));
    }
    return vnode;
}
