/**
 * @fileoverview Simplified Virtual DOM — diff / patch for lightweight
 *               component rendering driven by RazyUI state.
 * @module module/SPA/vdom
 */

// ── VNode types ──────────────────────────────────
const TEXT  = '#text';

/**
 * Create a virtual node.
 * @param {string} tag      — element tag name, or '#text'
 * @param {object} [props]  — attributes / event handlers
 * @param {Array}  [children]
 * @returns {object}
 */
export function h(tag, props, ...children) {
    // Allow h(tag, child1, child2) shorthand (no props)
    if (props && (typeof props === 'string' || typeof props === 'number' || props._vnode || Array.isArray(props))) {
        children = [props, ...children];
        props = {};
    }
    props = props || {};

    // Flatten & normalise children
    const flat = [];
    for (const c of children.flat(Infinity)) {
        if (c == null || c === false || c === true) continue;
        flat.push(typeof c === 'object' && c._vnode ? c : { _vnode: true, tag: TEXT, props: {}, children: [], text: String(c) });
    }

    return { _vnode: true, tag, props, children: flat };
}

// ── Render VNode → real DOM ──────────────────────

/**
 * Create a real DOM tree from a VNode.
 * @param {object} vnode
 * @returns {Node}
 */
export function createElement(vnode) {
    if (vnode.tag === TEXT) {
        return document.createTextNode(vnode.text ?? '');
    }

    const el = document.createElement(vnode.tag);
    applyProps(el, {}, vnode.props);
    for (const child of vnode.children) {
        el.appendChild(createElement(child));
    }
    return el;
}

// ── Diff / Patch ─────────────────────────────────

/**
 * Diff two VNode trees and patch the real DOM in-place.
 * @param {Node}   parent
 * @param {object} prev   — old VNode (may be null)
 * @param {object} next   — new VNode (may be null)
 * @param {number} [index=0]
 */
export function patch(parent, prev, next, index = 0) {
    const existing = parent.childNodes[index];

    // ── Add ──
    if (!prev) {
        if (next) parent.appendChild(createElement(next));
        return;
    }

    // ── Remove ──
    if (!next) {
        if (existing) parent.removeChild(existing);
        return;
    }

    // ── Replace (different tag or text change) ──
    if (changed(prev, next)) {
        parent.replaceChild(createElement(next), existing);
        return;
    }

    // ── Same element — diff props + children ──
    if (next.tag !== TEXT) {
        applyProps(existing, prev.props, next.props);
        diffChildren(existing, prev.children, next.children);
    }
}

/**
 * Diff two children arrays and patch.
 * @param {Node}  parent
 * @param {Array} oldCh
 * @param {Array} newCh
 */
function diffChildren(parent, oldCh, newCh) {
    const max = Math.max(oldCh.length, newCh.length);
    for (let i = 0; i < max; i++) {
        patch(parent, oldCh[i] || null, newCh[i] || null, i);
    }
}

/**
 * Test whether two VNodes require a full replacement.
 * @param {object} a
 * @param {object} b
 * @returns {boolean}
 */
function changed(a, b) {
    if (a.tag !== b.tag) return true;
    if (a.tag === TEXT) return a.text !== b.text;
    return false;
}

// ── Props helpers ────────────────────────────────

/**
 * Apply / diff props onto a real DOM element.
 * @param {HTMLElement} el
 * @param {object} oldP
 * @param {object} newP
 */
function applyProps(el, oldP, newP) {
    // Remove old
    for (const key of Object.keys(oldP)) {
        if (!(key in newP)) removeProp(el, key, oldP[key]);
    }
    // Set new / changed
    for (const [key, val] of Object.entries(newP)) {
        if (oldP[key] !== val) setProp(el, key, val, oldP[key]);
    }
}

function setProp(el, key, val, oldVal) {
    if (key === 'className') {
        el.className = val ?? '';
    } else if (key === 'style' && typeof val === 'object') {
        Object.assign(el.style, val);
    } else if (key.startsWith('on') && key.length > 2) {
        const event = key.slice(2).toLowerCase();
        if (typeof oldVal === 'function') el.removeEventListener(event, oldVal);
        if (typeof val === 'function') el.addEventListener(event, val);
    } else if (key === 'checked' || key === 'value' || key === 'disabled') {
        el[key] = val;
    } else if (typeof val === 'boolean') {
        if (val) el.setAttribute(key, '');
        else el.removeAttribute(key);
    } else {
        el.setAttribute(key, val);
    }
}

function removeProp(el, key, oldVal) {
    if (key.startsWith('on') && key.length > 2) {
        const event = key.slice(2).toLowerCase();
        if (typeof oldVal === 'function') el.removeEventListener(event, oldVal);
    } else if (key === 'className') {
        el.className = '';
    } else {
        el.removeAttribute(key);
    }
}
